type PlainObject = Record<string, unknown>;
type FlattenedObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map || value instanceof Set) return false;
  return true;
}

function flattenObject(
  obj: PlainObject,
  prefix = "",
  visited = new WeakSet<object>()
): FlattenedObject {
  if (!isPlainObject(obj)) {
    return prefix ? { [prefix]: obj } : {};
  }

  if (visited.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  visited.add(obj);

  const result: FlattenedObject = {};
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty-object leaf so the key isn't silently dropped
    if (prefix) result[prefix] = {};
    visited.delete(obj);
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const nested = flattenObject(value, flatKey, visited);
      Object.assign(result, nested);
    } else {
      result[flatKey] = value;
    }
  }

  visited.delete(obj);
  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const validateRange = (value: number, min: number, max: number, context: string): void => {
  if (value < min || value > max) {
    throw new RangeError(`${context}: value ${value} is out of range [${min}, ${max}]`);
  }
};

const parseNumber = (token: string, config: FieldConfig, fieldName: string): number => {
  const value = parseInt(token, 10);
  if (isNaN(value)) throw new SyntaxError(`${fieldName}: invalid number "${token}"`);
  validateRange(value, config.min, config.max, fieldName);
  return value;
};

const expandRange = (start: number, end: number, step: number, config: FieldConfig, fieldName: string): number[] => {
  if (start > end) throw new RangeError(`${fieldName}: range start ${start} exceeds end ${end}`);
  validateRange(start, config.min, config.max, fieldName);
  validateRange(end, config.min, config.max, fieldName);
  if (step < 1) throw new RangeError(`${fieldName}: step must be >= 1`);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
};

const parseToken = (token: string, config: FieldConfig, fieldName: string): number[] => {
  const { min, max } = config;

  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`${fieldName}: invalid step "${stepPart}"`);

    if (rangePart === "*") {
      return expandRange(min, max, step, config, fieldName);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseNumber(startStr, config, fieldName);
      const end = parseNumber(endStr, config, fieldName);
      return expandRange(start, end, step, config, fieldName);
    }

    const start = parseNumber(rangePart, config, fieldName);
    return expandRange(start, max, step, config, fieldName);
  }

  if (token === "*") {
    return expandRange(min, max, 1, config, fieldName);
  }

  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = parseNumber(startStr, config, fieldName);
    const end = parseNumber(endStr, config, fieldName);
    return expandRange(start, end, 1, config, fieldName);
  }

  return [parseNumber(token, config, fieldName)];
};

const parseField = (expression: string, config: FieldConfig, fieldName: string): number[] => {
  const parts = expression.split(",");
  const allValues = new Set<number>();

  for (const part of parts) {
    const values = parseToken(part.trim(), config, fieldName);
    for (const v of values) allValues.add(v);
  }

  return [...allValues].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronFields => {
  if (typeof expression !== "string") throw new TypeError("Cron expression must be a string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Cron expression must have exactly 5 fields, got ${fields.length}`);
  }

  return FIELD_ORDER.reduce((result, fieldName, index) => {
    const config = FIELD_CONFIGS[fieldName];
    let values = parseField(fields[index], config, fieldName);

    // Normalize dayOfWeek: treat 7 as 0 (both represent Sunday)
    if (fieldName === "dayOfWeek") {
      values = [...new Set(values.map((v) => (v === 7 ? 0 : v)))].sort((a, b) => a - b);
    }

    return { ...result, [fieldName]: values };
  }, {} as CronFields);
};

export default parseCron;

