type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = undefined;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = undefined;
    }
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject({ [key]: value } as unknown as NestedObject, prefix, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const generateRange = (min: number, max: number, step = 1): number[] => {
  const values: number[] = [];
  for (let i = min; i <= max; i += step) {
    values.push(i);
  }
  return values;
};

const validateValue = (value: number, field: FieldName): number => {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}-${max}] for field "${field}"`);
  }
  return value;
};

const parseToken = (token: string, field: FieldName): number[] => {
  const { min, max } = FIELD_RANGES[field];

  if (token === "*") {
    return generateRange(min, max);
  }

  if (token.startsWith("*/")) {
    const step = parseInt(token.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in token "${token}" for field "${field}"`);
    }
    return generateRange(min, max, step);
  }

  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in token "${token}" for field "${field}"`);
    }
    const [rangeStart, rangeEnd] = rangePart.split("-").map(n => parseInt(n, 10));
    if (isNaN(rangeStart) || isNaN(rangeEnd)) {
      throw new Error(`Invalid range in token "${token}" for field "${field}"`);
    }
    validateValue(rangeStart, field);
    validateValue(rangeEnd, field);
    if (rangeStart > rangeEnd) {
      throw new Error(`Range start ${rangeStart} > end ${rangeEnd} in field "${field}"`);
    }
    return generateRange(rangeStart, rangeEnd, step);
  }

  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${token}" for field "${field}"`);
    }
    validateValue(start, field);
    validateValue(end, field);
    if (start > end) {
      throw new Error(`Range start ${start} > end ${end} in field "${field}"`);
    }
    return generateRange(start, end);
  }

  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${token}" for field "${field}"`);
  }
  validateValue(value, field);
  return [value];
};

const parseField = (expression: string, field: FieldName): number[] => {
  const tokens = expression.split(",");
  const values = new Set<number>();

  for (const token of tokens) {
    for (const value of parseToken(token.trim(), field)) {
      values.add(value);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
};

const parseCron = (expression: string): ParsedCron => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
};

export default parseCron;

