type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type FlatValue = Primitive | unknown[] | Date | RegExp | Function;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: FlatValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  return true;
}

export default function flattenObject(
  input: unknown,
  prefix = "",
  visited = new WeakSet<object>()
): FlatObject {
  if (!isPlainObject(input)) {
    return prefix !== "" ? { [prefix]: input as FlatValue } : {};
  }

  if (visited.has(input)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  const keys = Object.keys(input);

  // Treat empty objects as leaf values to avoid silent key loss
  if (keys.length === 0) {
    return prefix !== "" ? { [prefix]: input as FlatValue } : {};
  }

  visited.add(input);

  const result: FlatObject = {};

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const value = input[key];
    const fullKey = prefix !== "" ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      const nested = flattenObject(value, fullKey, visited);
      for (const nestedKey of Object.keys(nested)) {
        result[nestedKey] = nested[nestedKey];
      }
    } else {
      result[fullKey] = value as FlatValue;
    }
  }

  visited.delete(input);

  return result;
}

const FIELD_RANGES: Record<string, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function expandRange(start: number, end: number): number[] {
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function validateValue(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}-${max}] for field "${field}"`);
  }
}

function parseField(expr: string, field: string): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr === "*") {
    return expandRange(min, max);
  }

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value in "${expr}" for field "${field}"`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value in "${expr}" for field "${field}"`);
    let rangeStart = min;
    let rangeEnd = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        validateValue(s, min, max, field);
        validateValue(e, min, max, field);
        rangeStart = s;
        rangeEnd = e;
      } else {
        rangeStart = parseInt(rangePart, 10);
        validateValue(rangeStart, min, max, field);
        rangeEnd = max;
      }
    }
    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) result.push(i);
    return result;
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${expr}" for field "${field}"`);
    validateValue(start, min, max, field);
    validateValue(end, min, max, field);
    return expandRange(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${expr}" for field "${field}"`);
  validateValue(value, min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) {
    return result;
  }

  if (typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) {
      result[prefix] = obj as Primitive | unknown[];
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0 && prefix) {
    result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const sanitizedKey = String(key);
    const newKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function flattenObject(obj: NestedObject, prefix = ""): FlatObject {
  const result: FlatObject = {};

  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      Object.assign(result, flattenObject(value as NestedObject, fullKey));
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

export default flattenObject;

type CronField = {
  min: number;
  max: number;
};

const FIELD_RANGES: Record<string, CronField> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = field;

  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepPart}`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [rangeStart, rangeEnd] = rangePart.split("-").map(Number);
        start = clamp(rangeStart, min, max);
        end = clamp(rangeEnd, min, max);
        if (start > end) throw new RangeError(`Invalid range: ${rangePart}`);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new RangeError(`Invalid range: ${expr}`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: ${expr}`);
  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  const dayOfWeekValues = parseField(dowExpr, FIELD_RANGES.dayOfWeek);
  const normalizedDow = dayOfWeekValues
    .map((v) => (v === 7 ? 0 : v))
    .filter((v, i, arr) => arr.indexOf(v) === i)
    .sort((a, b) => a - b);

  return {
    minute: parseField(minuteExpr, FIELD_RANGES.minute),
    hour: parseField(hourExpr, FIELD_RANGES.hour),
    dayOfMonth: parseField(domExpr, FIELD_RANGES.dayOfMonth),
    month: parseField(monthExpr, FIELD_RANGES.month),
    dayOfWeek: normalizedDow,
  };
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function intRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInBounds(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} in "${context}" is out of bounds [${config.min}, ${config.max}]`
    );
  }
}

function parseStep(expr: string, config: FieldConfig): number[] {
  const slashIdx = expr.indexOf('/');
  const rangePart = expr.slice(0, slashIdx);
  const stepStr = expr.slice(slashIdx + 1);
  const step = parseInt(stepStr, 10);

  if (isNaN(step) || step <= 0 || String(step) !== stepStr) {
    throw new SyntaxError(`Invalid step value in "${expr}"`);
  }

  let start: number;
  let end: number;

  if (rangePart === '*') {
    start = config.min;
    end = config.max;
  } else if (rangePart.includes('-')) {
    [start, end] = parseRangeBounds(rangePart, config);
  } else {
    const n = parseInt(rangePart, 10);
    if (isNaN(n) || String(n) !== rangePart) {
      throw new SyntaxError(`Invalid step start in "${expr}"`);
    }
    assertInBounds(n, config, expr);
    start = n;
    end = config.max;
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) values.push(i);
  return values;
}

function parseRangeBounds(expr: string, config: FieldConfig): [number, number] {
  const dashIdx = expr.indexOf('-');
  const startStr = expr.slice(0, dashIdx);
  const endStr = expr.slice(dashIdx + 1);
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);

  if (isNaN(start) || String(start) !== startStr) {
    throw new SyntaxError(`Invalid range start in "${expr}"`);
  }
  if (isNaN(end) || String(end) !== endStr) {
    throw new SyntaxError(`Invalid range end in "${expr}"`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in "${expr}"`);
  }
  assertInBounds(start, config, expr);
  assertInBounds(end, config, expr);

  return [start, end];
}

function parseAtom(expr: string, config: FieldConfig): number[] {
  if (expr === '*') {
    return intRange(config.min, config.max);
  }
  if (expr.includes('/')) {
    return parseStep(expr, config);
  }
  if (expr.includes('-')) {
    const [start, end] = parseRangeBounds(expr, config);
    return intRange(start, end);
  }

  const n = parseInt(expr, 10);
  if (isNaN(n) || String(n) !== expr) {
    throw new SyntaxError(`Invalid cron value "${expr}"`);
  }
  assertInBounds(n, config, expr);
  return [n];
}

function parseField(expr: string, config: FieldConfig): number[] {
  if (expr.includes(',')) {
    const seen = new Set<number>();
    for (const part of expr.split(',')) {
      const trimmed = part.trim();
      if (trimmed === '') throw new SyntaxError(`Empty element in list "${expr}"`);
      for (const v of parseAtom(trimmed, config)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }
  return parseAtom(expr, config);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== 'string') {
    throw new TypeError('Cron expression must be a string');
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length} in "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, FIELD_CONFIGS.minute),
    hour:       parseField(hourExpr,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domExpr,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthExpr,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowExpr,    FIELD_CONFIGS.dayOfWeek),
  };
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

const FIELD_ORDER: readonly CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const NON_NEGATIVE_INT_RE = /^\d+$/;

function strictParseInt(raw: string, context: string): number {
  if (!NON_NEGATIVE_INT_RE.test(raw)) {
    throw new Error(`"${raw}" is not a valid non-negative integer in: "${context}"`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`"${raw}" overflows safe integer range in: "${context}"`);
  }
  return n;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of valid range [${min}–${max}] in: "${context}"`
    );
  }
}

function generateSequence(start: number, end: number, step: number): number[] {
  // Defensive guard: step must be positive and non-zero to prevent infinite loops.
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got: ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseToken(
  token: string,
  min: number,
  max: number,
  depth: number = 0
): number[] {
  // Guard against pathological recursive expansion from crafted expressions.
  if (depth > 3) {
    throw new Error(`Excessive nesting depth in token: "${token}"`);
  }

  const t = token.trim();

  if (t === "") {
    throw new Error("Encountered empty token — check for trailing commas or extra spaces");
  }

  // ── Wildcard ──────────────────────────────────────────────────────────────
  if (t === "*") {
    return generateSequence(min, max, 1);
  }

  // ── Step value: */n  |  start/n  |  start-end/n ──────────────────────────
  // Use lastIndexOf so that a range like "1-5/2" is split correctly at the
  // trailing slash rather than a potential ambiguous position.
  const slashIdx = t.indexOf("/");
  if (slashIdx !== -1) {
    const baseExpr = t.slice(0, slashIdx);
    const stepRaw  = t.slice(slashIdx + 1);

    if (baseExpr === "" || stepRaw === "") {
      throw new Error(`Malformed step expression: "${t}"`);
    }

    const step = strictParseInt(stepRaw, t);
    if (step === 0) {
      throw new Error(`Step value of 0 is not allowed in: "${t}"`);
    }

    let rangeStart: number;
    let rangeEnd:   number;

    if (baseExpr === "*") {
      rangeStart = min;
      rangeEnd   = max;
    } else if (baseExpr.includes("-")) {
      const dashIdx = baseExpr.indexOf("-");
      const lo = baseExpr.slice(0, dashIdx);
      const hi = baseExpr.slice(dashIdx + 1);

      if (lo === "" || hi === "") {
        throw new Error(`Malformed range in step base: "${baseExpr}"`);
      }

      rangeStart = strictParseInt(lo, t);
      rangeEnd   = strictParseInt(hi, t);
    } else {
      rangeStart = strictParseInt(baseExpr, t);
      rangeEnd   = max;
    }

    assertInRange(rangeStart, min, max, t);
    assertInRange(rangeEnd,   min, max, t);

    if (rangeStart > rangeEnd) {
      throw new Error(
        `Range start (${rangeStart}) exceeds end (${rangeEnd}) in: "${t}"`
      );
    }

    return generateSequence(rangeStart, rangeEnd, step);
  }

  // ── Comma-separated list ──────────────────────────────────────────────────
  // Split before range-check to allow "1-3,5,7" style expressions.
  if (t.includes(",")) {
    const parts = t.split(",");

    if (parts.some((p) => p.trim() === "")) {
      throw new Error(`Empty element in comma list: "${t}"`);
    }

    const seen = new Set<number>();
    for (const part of parts) {
      const expanded = parseToken(part.trim(), min, max, depth + 1);
      for (const v of expanded) {
        seen.add(v);
      }
    }

    return Array.from(seen).sort((a, b) => a - b);
  }

  // ── Range: n-m ───────────────────────────────────────────────────────────
  if (t.includes("-")) {
    const dashIdx = t.indexOf("-");
    const lo = t.slice(0, dashIdx);
    const hi = t.slice(dashIdx + 1);

    if (lo === "" || hi === "") {
      throw new Error(`Malformed range (empty boundary): "${t}"`);
    }

    // Reject double-dash or embedded dashes that would indicate a malformed token.
    if (hi.includes("-")) {
      throw new Error(`Unexpected extra dash in range: "${t}"`);
    }

    const start = strictParseInt(lo, t);
    const end   = strictParseInt(hi, t);

    assertInRange(start, min, max, t);
    assertInRange(end,   min, max, t);

    if (start > end) {
      throw new Error(`Range start (${start}) exceeds end (${end}) in: "${t}"`);
    }

    return generateSequence(start, end, 1);
  }

  // ── Single numeric value ─────────────────────────────────────────────────
  const value = strictParseInt(t, t);
  assertInRange(value, min, max, t);
  return [value];
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received: ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  // Collapse multiple whitespace characters between fields.
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields; got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const { min, max } = FIELD_RANGES[fieldName];
    const raw = fields[i];

    try {
      const values = parseToken(raw, min, max);

      if (values.length === 0) {
        throw new Error("Parsed to an empty set of values — this is a bug");
      }

      result[fieldName] = values;
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new Error(
        `Invalid ${fieldName} field "${raw}" (valid range ${FIELD_RANGES[fieldName].min}–${FIELD_RANGES[fieldName].max}): ${msg}`
      );
    }
  }

  return result;
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function unique(arr: number[]): number[] {
  return [...new Set(arr)].sort((a, b) => a - b);
}

function validateValue(value: number, field: FieldName): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}-${max}] for field "${field}"`);
  }
}

function parseSegment(segment: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (segment === "*") {
    return range(min, max);
  }

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${segment}" for field "${field}"`);
    }
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${segment}" for field "${field}"`);
    }
    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        [start, end] = rangePart.split("-").map((v) => parseInt(v, 10));
      } else {
        start = parseInt(rangePart, 10);
        end = max;
      }
    }
    validateValue(start, field);
    validateValue(end, field);
    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" for field "${field}"`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" for field "${field}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in "${segment}" for field "${field}"`);
    }
    validateValue(start, field);
    validateValue(end, field);
    return range(start, end);
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" for field "${field}"`);
  }
  validateValue(value, field);
  return [value];
}

function parseField(expression: string, field: FieldName): number[] {
  const segments = expression.split(",");
  const values: number[] = [];
  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), field);
    values.push(...parsed);
  }
  const result = unique(values);
  // Normalize dayOfWeek: treat 7 as 0 (both are Sunday)
  if (field === "dayOfWeek") {
    const normalized = unique(result.map((v) => (v === 7 ? 0 : v)));
    return normalized;
  }
  return result;
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new CronParseError(
      `Value ${value} out of range [${min}, ${max}] in ${context}`
    );
  }
}

function normalizeRange(values: number[], min: number, max: number): number[] {
  return [...new Set(values.map((v) => (v === 7 && max === 7 ? 0 : v)))].filter(
    (v) => v >= min && v <= (max === 7 ? 6 : max)
  ).sort((a, b) => a - b);
}

function expandWildcard(min: number, max: number): number[] {
  const effectiveMax = max === 7 ? 6 : max;
  return Array.from({ length: effectiveMax - min + 1 }, (_, i) => i + min);
}

function parseStep(expression: string, min: number, max: number, fieldName: CronField): number[] {
  const [rangeOrWildcard, stepStr] = expression.split("/");

  if (stepStr === undefined || stepStr === "") {
    throw new CronParseError(`Missing step value after '/' in field '${fieldName}'`);
  }

  const step = Number(stepStr);
  if (!Number.isInteger(step) || step <= 0) {
    throw new CronParseError(
      `Invalid step value '${stepStr}' in field '${fieldName}': must be a positive integer`
    );
  }

  let start: number;
  let end: number;

  if (rangeOrWildcard === "*") {
    start = min;
    end = max === 7 ? 6 : max;
  } else if (rangeOrWildcard.includes("-")) {
    const [startStr, endStr] = rangeOrWildcard.split("-");
    start = Number(startStr);
    end = Number(endStr);
    assertInRange(start, min, max, `field '${fieldName}'`);
    assertInRange(end, min, max, `field '${fieldName}'`);
    if (start > end) {
      throw new CronParseError(
        `Range start ${start} exceeds end ${end} in field '${fieldName}'`
      );
    }
    end = end === 7 && max === 7 ? 6 : end;
  } else {
    start = Number(rangeOrWildcard);
    assertInRange(start, min, max, `field '${fieldName}'`);
    end = max === 7 ? 6 : max;
  }

  const results: number[] = [];
  for (let v = start; v <= end; v += step) {
    results.push(v === 7 && max === 7 ? 0 : v);
  }

  return [...new Set(results)].sort((a, b) => a - b);
}

function parseRange(expression: string, min: number, max: number, fieldName: CronField): number[] {
  const parts = expression.split("-");
  if (parts.length !== 2) {
    throw new CronParseError(
      `Invalid range '${expression}' in field '${fieldName}': expected format 'a-b'`
    );
  }

  const start = Number(parts[0]);
  const end = Number(parts[1]);

  if (!Number.isFinite(start) || !Number.isFinite(end)) {
    throw new CronParseError(
      `Non-numeric value in range '${expression}' in field '${fieldName}'`
    );
  }

  assertInRange(start, min, max, `field '${fieldName}'`);
  assertInRange(end, min, max, `field '${fieldName}'`);

  if (start > end) {
    throw new CronParseError(
      `Range start ${start} exceeds end ${end} in field '${fieldName}'`
    );
  }

  return Array.from({ length: end - start + 1 }, (_, i) => {
    const v = i + start;
    return v === 7 && max === 7 ? 0 : v;
  }).filter((v, i, arr) => arr.indexOf(v) === i).sort((a, b) => a - b);
}

function parseSingleToken(
  token: string,
  min: number,
  max: number,
  fieldName: CronField
): number[] {
  if (token === "") {
    throw new CronParseError(`Empty token in field '${fieldName}'`);
  }

  if (token === "*") {
    return expandWildcard(min, max);
  }

  if (token.includes("/")) {
    return parseStep(token, min, max, fieldName);
  }

  if (token.includes("-")) {
    return parseRange(token, min, max, fieldName);
  }

  const value = Number(token);
  if (!Number.isFinite(value) || !Number.isInteger(value)) {
    throw new CronParseError(
      `Invalid value '${token}' in field '${fieldName}': must be an integer`
    );
  }

  assertInRange(value, min, max, `field '${fieldName}'`);
  const normalized = value === 7 && max === 7 ? 0 : value;
  return [normalized];
}

function parseField(expression: string, fieldName: CronField): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  if (expression === undefined || expression === "") {
    throw new CronParseError(`Missing expression for field '${fieldName}'`);
  }

  const tokens = expression.split(",");

  if (tokens.some((t) => t === "")) {
    throw new CronParseError(
      `Empty token due to consecutive or trailing commas in field '${fieldName}'`
    );
  }

  const values = tokens.flatMap((token) =>
    parseSingleToken(token.trim(), min, max, fieldName)
  );

  const unique = normalizeRange(values, min, max);

  if (unique.length === 0) {
    throw new CronParseError(
      `No valid values resolved for field '${fieldName}'`
    );
  }

  return unique;
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new CronParseError("Cron expression must be a string");
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], fieldName);
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronFields;
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function buildRange(start: number, end: number, step: number = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  if (start > end) throw new Error(`Range start ${start} exceeds end ${end}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(val: number, min: number, max: number, context: string): void {
  if (val < min || val > max) {
    throw new Error(`Value ${val} out of valid range [${min}, ${max}] in "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const slashIndex = segment.indexOf("/");

  if (slashIndex !== -1) {
    const base = segment.slice(0, slashIndex);
    const stepRaw = segment.slice(slashIndex + 1);

    if (stepRaw.includes("/")) {
      throw new Error(`Invalid step expression: "${segment}"`);
    }

    const step = parseInt(stepRaw, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value "${stepRaw}" in "${segment}"`);
    }

    if (base === "*") {
      return buildRange(min, max, step);
    }

    if (base.includes("-")) {
      const dashParts = base.split("-");
      if (dashParts.length !== 2) throw new Error(`Invalid range "${base}" in "${segment}"`);
      const start = parseInt(dashParts[0], 10);
      const end = parseInt(dashParts[1], 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Non-numeric range bounds in "${segment}"`);
      assertInRange(start, min, max, segment);
      assertInRange(end, min, max, segment);
      return buildRange(start, end, step);
    }

    throw new Error(`Invalid base expression "${base}" in "${segment}"`);
  }

  if (segment === "*") {
    return buildRange(min, max);
  }

  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) throw new Error(`Invalid range expression: "${segment}"`);
    const start = parseInt(dashParts[0], 10);
    const end = parseInt(dashParts[1], 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Non-numeric range bounds in "${segment}"`);
    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);
    return buildRange(start, end);
  }

  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value "${segment}"`);
  assertInRange(val, min, max, segment);
  return [val];
}

function parseField(expr: string, min: number, max: number): number[] {
  const parts = expr.split(",");

  if (parts.length === 1) {
    return parseSegment(expr.trim(), min, max);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") throw new Error(`Empty element in list expression "${expr}"`);
    for (const v of parseSegment(trimmed, min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(`Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`);
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    try {
      result[name] = parseField(parts[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid ${name} field "${parts[i]}": ${err instanceof Error ? err.message : String(err)}`
      );
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix: string = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type NestedObject = {
  [key: string]: unknown;
};

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  ancestors: WeakSet<object>,
  result: Record<string, unknown>
): void {
  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      if (ancestors.has(value)) {
        throw new TypeError(
          `Circular reference detected at key: "${fullKey}"`
        );
      }

      // Empty plain objects are preserved as leaf values to avoid silent data loss
      if (Object.keys(value).length === 0) {
        result[fullKey] = value;
      } else {
        ancestors.add(value);
        flattenObjectInternal(value, fullKey, ancestors, result);
        ancestors.delete(value);
      }
    } else {
      result[fullKey] = value;
    }
  }
}

export default function flattenObject(
  obj: NestedObject
): Record<string, unknown> {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `Expected a plain object, received: ${obj === null ? "null" : typeof obj}`
    );
  }

  const result: Record<string, unknown> = {};
  const ancestors = new WeakSet<object>();
  ancestors.add(obj);
  flattenObjectInternal(obj, "", ancestors, result);
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : String(index);
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clampDayOfWeek(values: number[]): number[] {
  // Normalize 7 (Sunday alias) to 0, deduplicate, sort
  return [...new Set(values.map((v) => (v === 7 ? 0 : v)))].sort(
    (a, b) => a - b
  );
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  const assertInRange = (n: number): number => {
    if (!Number.isInteger(n) || n < min || n > max) {
      throw new RangeError(
        `Value ${n} out of range [${min}, ${max}] for field "${field}"`
      );
    }
    return n;
  };

  const expand = (lo: number, hi: number, step: number): number[] => {
    if (step < 1) throw new RangeError(`Step must be >= 1, got ${step}`);
    const result: number[] = [];
    for (let i = lo; i <= hi; i += step) result.push(i);
    return result;
  };

  // Comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const parts = expr.split(",");
    if (parts.some((p) => p.trim() === ""))
      throw new SyntaxError(`Empty segment in list for field "${field}"`);
    const merged = parts.flatMap((part) => parseField(part.trim(), field));
    return [...new Set(merged)].sort((a, b) => a - b);
  }

  // Wildcard with optional step: * or */N
  if (expr.startsWith("*")) {
    if (expr === "*") return expand(min, max, 1);
    const slashParts = expr.split("/");
    if (slashParts.length !== 2 || slashParts[0] !== "*")
      throw new SyntaxError(`Invalid expression "${expr}" for field "${field}"`);
    const step = Number(slashParts[1]);
    if (!Number.isInteger(step) || step < 1)
      throw new RangeError(`Invalid step "${slashParts[1]}" for field "${field}"`);
    return expand(min, max, step);
  }

  // Range with optional step: A-B or A-B/N
  if (expr.includes("-")) {
    const [rangePart, stepPart] = expr.split("/");
    const [loStr, hiStr] = rangePart.split("-");
    if (loStr === undefined || hiStr === undefined || loStr === "" || hiStr === "")
      throw new SyntaxError(`Invalid range "${expr}" for field "${field}"`);
    const lo = assertInRange(Number(loStr));
    const hi = assertInRange(Number(hiStr));
    if (lo > hi)
      throw new RangeError(
        `Range start ${lo} > end ${hi} for field "${field}"`
      );
    const step = stepPart !== undefined ? Number(stepPart) : 1;
    if (!Number.isInteger(step) || step < 1)
      throw new RangeError(`Invalid step "${stepPart}" for field "${field}"`);
    return expand(lo, hi, step);
  }

  // Step without wildcard: N/S (start from N, step S, up to max)
  if (expr.includes("/")) {
    const [startStr, stepStr] = expr.split("/");
    const start = assertInRange(Number(startStr));
    const step = Number(stepStr);
    if (!Number.isInteger(step) || step < 1)
      throw new RangeError(`Invalid step "${stepStr}" for field "${field}"`);
    return expand(start, max, step);
  }

  // Plain number
  const n = Number(expr);
  if (!Number.isFinite(n) || !Number.isInteger(n))
    throw new SyntaxError(`Non-integer value "${expr}" for field "${field}"`);
  return [assertInRange(n)];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string")
    throw new TypeError("Cron expression must be a string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields as [
    string,
    string,
    string,
    string,
    string
  ];

  const dayOfWeekRaw = parseField(dowExpr, "dayOfWeek");

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: clampDayOfWeek(dayOfWeekRaw),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<keyof CronFields, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function generateRange(start: number, end: number, step = 1): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function dedupeSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, range: FieldRange): number[] {
  const { min, max } = range;

  // Wildcard: *
  if (segment === "*") {
    return generateRange(min, max);
  }

  // Step with wildcard: */N
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) throw new Error(`Invalid step value: ${step}`);
    return generateRange(min, max, step);
  }

  // Step with range: N-M/S
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const start = parseInt(stepRangeMatch[1], 10);
    const end   = parseInt(stepRangeMatch[2], 10);
    const step  = parseInt(stepRangeMatch[3], 10);
    if (start < min || end > max) throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}]`);
    if (start > end) throw new Error(`Range start ${start} > end ${end}`);
    if (step < 1) throw new Error(`Invalid step value: ${step}`);
    return generateRange(start, end, step);
  }

  // Range: N-M
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    if (start < min || end > max) throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}]`);
    if (start > end) throw new Error(`Range start ${start} > end ${end}`);
    return generateRange(start, end);
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    if (value < min || value > max) throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
    return [value];
  }

  throw new Error(`Unrecognized cron segment: "${segment}"`);
}

function parseField(field: string, range: FieldRange): number[] {
  const segments = field.split(",");
  if (segments.length === 0) throw new Error("Empty cron field");

  const values = segments.flatMap((segment) => parseSegment(segment.trim(), range));
  return dedupeSort(values);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") throw new Error("Cron expression must be a string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;

  const minute     = parseField(minuteStr, FIELD_RANGES.minute);
  const hour       = parseField(hourStr,   FIELD_RANGES.hour);
  const dayOfMonth = parseField(domStr,    FIELD_RANGES.dayOfMonth);
  const month      = parseField(monthStr,  FIELD_RANGES.month);

  // dayOfWeek: 7 is treated as Sunday (same as 0), normalize to 0
  const rawDow = parseField(dowStr, FIELD_RANGES.dayOfWeek);
  const dayOfWeek = dedupeSort(rawDow.map((v) => (v === 7 ? 0 : v)));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value) ? JSON.stringify(value) : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

export default function flattenObject(obj: NestedObject, prefix = ""): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    return prefix ? { [prefix]: obj as Primitive | Array<unknown> } : {};
  }

  return Object.entries(obj).reduce<FlatObject>((acc, [key, value]) => {
    const flatKey = prefix ? `${prefix}.${key}` : key;
    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      Object.assign(acc, flattenObject(value as NestedObject, flatKey));
    } else {
      acc[flatKey] = value as Primitive | Array<unknown>;
    }
    return acc;
  }, {});
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const clampToRange = (values: number[], min: number, max: number): number[] =>
  [...new Set(values.filter(v => v >= min && v <= max))].sort((a, b) => a - b);

const expandRange = (start: number, end: number): number[] => {
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
};

const parseSegment = (segment: string, min: number, max: number): number[] => {
  if (segment === "*") return expandRange(min, max);

  if (segment.includes("/")) {
    const [rangepart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${stepStr}`);

    const base = rangepart === "*" ? expandRange(min, max) : parseSegment(rangepart, min, max);
    return base.filter(v => (v - base[0]) % step === 0);
  }

  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    return expandRange(start, end);
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${segment}`);
  return [value];
};

const parseField = (field: string, fieldName: FieldName): number[] => {
  const { min, max } = FIELD_RANGES[fieldName];

  const values = field
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), min, max));

  const result = clampToRange(values, min, max);

  if (result.length === 0) throw new Error(`No valid values for field ${fieldName}: "${field}"`);

  return result;
};

const parseCron = (expression: string): ParsedCron => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;

  return {
    minute: parseField(minuteField, "minute"),
    hour: parseField(hourField, "hour"),
    dayOfMonth: parseField(dayOfMonthField, "dayOfMonth"),
    month: parseField(monthField, "month"),
    dayOfWeek: parseField(dayOfWeekField, "dayOfWeek"),
  };
};

