const range = (start: number, end: number, step = 1): number[] => {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
};

const validateValue = (value: number, field: FieldName): number => {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}-${max}] for field "${field}"`);
  }
  return value;
};

const parseSegment = (segment: string, field: FieldName): number[] => {
  const { min, max } = FIELD_RANGES[field];

  if (segment === "*") {
    return range(min, max);
