  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${segment}" for field "${field}"`);
    }
    return range(min, max, step);
  }

  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${segment}" for field "${field}"`);
    }
    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range in "${segment}" for field "${field}"`);
      }
      validateValue(start, field);
      validateValue(end, field);
      if (start > end) {
        throw new RangeError(`Range start ${start} exceeds end ${end} in "${segment}"`);
      }
      return range(start, end, step);
    }
    const start = parseInt(rangePart, 10);
    if (isNaN(start)) {
      throw new SyntaxError(`Invalid value in "${segment}" for field "${field}"`);
    }
    validateValue(start, field);
    return range(start, max, step);
  }

  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range in "${segment}" for field "${field}"`);
    }
    validateValue(start, field);
    validateValue(end, field);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${segment}"`);
    }
    return range(start, end);
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" for field "${field}"`);
  }
  validateValue(value, field);
  return [value];
};

const parseField = (expression: string, field: FieldName): number[] => {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), field);
    for (const v of parsed) {
      // Normalize dayOfWeek: treat 7 as 0 (Sunday)
      const normalized = field === "dayOfWeek" && v === 7 ? 0 : v;
      values.add(normalized);
    }
  }

  return [...values].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
