type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);
    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range/step in field "${field}": ${expr}`);
    if (start < min || end > max) throw new Error(`Value out of range in field "${field}": ${expr}`);
    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in field "${field}": ${expr}`);
    if (start < min || end > max || start > end) throw new Error(`Range out of bounds in field "${field}": ${expr}`);
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value in field "${field}": ${expr}`);
  if (value < min || value > max) throw new Error(`Value ${value} out of range [${min}-${max}] in field "${field}"`);
  return [value];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: Array<keyof CronFields> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of valid range [${min}-${max}] in field "${context}"`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step with wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) {
      throw new RangeError(`Step value must be >= 1 in field "${fieldName}"`);
    }
    return rangeArray(min, max, step);
  }

  // Range with optional step: start-end or start-end/step
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    const step  = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;

    assertInRange(start, min, max, fieldName);
    assertInRange(end,   min, max, fieldName);

    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`
      );
    }
    if (step < 1) {
      throw new RangeError(`Step value must be >= 1 in field "${fieldName}"`);
    }

    return rangeArray(start, end, step);
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    assertInRange(value, min, max, fieldName);
    return [value];
  }

  throw new SyntaxError(`Unrecognized segment "${segment}" in field "${fieldName}"`);
}

function parseField(expression: string, config: FieldConfig, fieldName: string): number[] {
  const segments = expression.split(",");

  if (segments.length === 0 || segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(`Empty or malformed list in field "${fieldName}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), config, fieldName)) {
      valueSet.add(value);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(fields[i], FIELD_CONFIGS[name], name);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function expandRange(start: number, end: number, step: number, min: number, max: number): number[] {
  if (start > end) throw new RangeError(`Range start ${start} is greater than end ${end}`);
  const values: number[] = [];
  for (let i = clamp(start, min, max); i <= clamp(end, min, max); i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step with wildcard: */n
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    if (step <= 0) throw new RangeError(`Step value must be positive, got ${step}`);
    return expandRange(min, max, step, min, max);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, min, max);
  }

  // Range with optional step: n-m or n-m/s
  if (/^\d+-\d+(\/\d+)?$/.test(segment)) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (step <= 0) throw new RangeError(`Step value must be positive, got ${step}`);
    return expandRange(start, end, step, min, max);
  }

  // Single number
  if (/^\d+$/.test(segment)) {
    const value = parseInt(segment, 10);
    // Special case: dayOfWeek 7 maps to 0 (Sunday)
    if (value === 7 && min === 0 && max === 7) return [0];
    return [clamp(value, min, max)];
  }

  throw new SyntaxError(`Invalid cron segment: "${segment}"`);
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const rawValues = parts.flatMap((part) => parseSegment(part.trim(), min, max));
  // Deduplicate and sort
  return [...new Set(rawValues)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  return {
    minute:     parseField(minuteField, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourField,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(domField,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthField,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  parseField(dowField,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const generateRange = (min: number, max: number, step = 1): number[] => {
  const values: number[] = [];
  for (let i = min; i <= max; i += step) {
    values.push(i);
  }
  return values;
};

const validateValue = (value: number, field: FieldName): number => {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}-${max}] for field "${field}"`);
  }
  return value;
};

const parseSegment = (segment: string, field: FieldName): number[] => {
  const { min, max } = FIELD_RANGES[field];

  if (segment === "*") {
    return generateRange(min, max);
  }

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${segment}" for field "${field}"`);
    }
    return generateRange(min, max, step);
  }

  if (segment.includes("-")) {
    const [startStr, rest] = segment.split("-");
    const [endStr, stepStr] = rest.includes("/") ? rest.split("/") : [rest, "1"];
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    const step = parseInt(stepStr, 10);

    if (isNaN(start) || isNaN(end) || isNaN(step)) {
      throw new Error(`Invalid range "${segment}" for field "${field}"`);
    }
    if (start > end) {
      throw new Error(`Range start ${start} > end ${end} for field "${field}"`);
    }
    validateValue(start, field);
    validateValue(end, field);

    return generateRange(start, end, step);
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${segment}" for field "${field}"`);
  }

  return [validateValue(value, field)];
};

const parseField = (expression: string, field: FieldName): number[] => {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), field)) {
      values.add(value);
    }
  }

  return [...values].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
};

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, field: CronField): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of valid range [${min}-${max}] for field "${field}"`
    );
  }
}

function expandRange(start: number, end: number, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  assertInRange(start, min, max, field);
  assertInRange(end, min, max, field);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} must not exceed end ${end} for field "${field}"`
    );
  }

  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function expandStep(rangeExpr: string, step: number, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(
      `Step value ${step} must be a positive integer for field "${field}"`
    );
  }

  let start = min;
  let end = max;

  if (rangeExpr !== "*") {
    const rangeParts = rangeExpr.split("-");
    if (rangeParts.length !== 2) {
      throw new SyntaxError(
        `Invalid range expression "${rangeExpr}" in step for field "${field}"`
      );
    }
    start = parseIntStrict(rangeParts[0], field);
    end = parseIntStrict(rangeParts[1], field);
    assertInRange(start, min, max, field);
    assertInRange(end, min, max, field);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} must not exceed end ${end} for field "${field}"`
      );
    }
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseIntStrict(raw: string, field: CronField): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(
      `Expected a non-negative integer but got "${trimmed}" in field "${field}"`
    );
  }
  return parseInt(trimmed, 10);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty segment encountered in field "${field}"`);
  }

  // Step expression: e.g. "*/15" or "1-5/2"
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid step expression "${trimmed}" in field "${field}"`
      );
    }
    const step = parseIntStrict(slashParts[1], field);
    return expandStep(slashParts[0], step, field);
  }

  // Wildcard
  if (trimmed === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: e.g. "1-5"
  if (trimmed.includes("-")) {
    const rangeParts = trimmed.split("-");
    if (rangeParts.length !== 2) {
      throw new SyntaxError(
        `Invalid range expression "${trimmed}" in field "${field}"`
      );
    }
    const start = parseIntStrict(rangeParts[0], field);
    const end = parseIntStrict(rangeParts[1], field);
    return expandRange(start, end, field);
  }

  // Single numeric value
  const value = parseIntStrict(trimmed, field);
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(raw: string, field: CronField): number[] {
  if (raw == null || raw.trim() === "") {
    throw new SyntaxError(`Missing or empty value for field "${field}"`);
  }

  const segments = raw.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const expanded = parseSegment(segment, field);
    for (const v of expanded) {
      // Normalize dayOfWeek: both 0 and 7 mean Sunday — canonicalize to 0
      const normalized =
        field === "dayOfWeek" && v === 7 ? 0 : v;
      valueSet.add(normalized);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseNumber(token: string, field: CronField): number {
  const value = Number(token);
  if (isNaN(value) || !Number.isFinite(value)) {
    throw new TypeError(
      `Invalid numeric value "${token}" for field "${field}"`
    );
  }
  assertInRange(value, field);
  return value;
}

function expandRange(start: number, end: number, field: CronField): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} for field "${field}"`
    );
  }
  assertInRange(start, field);
  assertInRange(end, field);
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function expandStep(base: string, step: number, field: CronField): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(
      `Step value ${step} must be a positive integer for field "${field}"`
    );
  }

  const { min, max } = FIELD_RANGES[field];
  let rangeStart: number;
  let rangeEnd: number;

  if (base === "*") {
    rangeStart = min;
    rangeEnd = max;
  } else if (base.includes("-")) {
    const parts = base.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(
        `Invalid range expression "${base}" for field "${field}"`
      );
    }
    rangeStart = parseNumber(parts[0], field);
    rangeEnd = parseNumber(parts[1], field);
    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start ${rangeStart} exceeds end ${rangeEnd} for field "${field}"`
      );
    }
  } else {
    rangeStart = parseNumber(base, field);
    rangeEnd = max;
  }

  const values: number[] = [];
  for (let i = rangeStart; i <= rangeEnd; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  if (segment.trim() === "") {
    throw new SyntaxError(`Empty segment encountered for field "${field}"`);
  }

  // Step expression: base/step
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid step expression "${segment}" for field "${field}"`
      );
    }
    const [base, stepStr] = slashParts;
    const step = Number(stepStr);
    if (isNaN(step) || !Number.isFinite(step)) {
      throw new TypeError(
        `Invalid step value "${stepStr}" for field "${field}"`
      );
    }
    return expandStep(base, step, field);
  }

  // Wildcard
  if (segment === "*") {
    const { min, max } = FIELD_RANGES[field];
    return expandRange(min, max, field);
  }

  // Range expression
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid range expression "${segment}" for field "${field}"`
      );
    }
    const start = parseNumber(dashParts[0], field);
    const end = parseNumber(dashParts[1], field);
    return expandRange(start, end, field);
  }

  // Plain number
  return [parseNumber(segment, field)];
}

function parseField(expression: string, field: CronField): number[] {
  if (expression === null || expression === undefined) {
    throw new TypeError(`Field expression for "${field}" is null or undefined`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Empty expression for field "${field}"`);
  }

  // Comma-separated list: each part processed independently
  const segments = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const expanded = parseSegment(segment.trim(), field);
    for (const value of expanded) {
      // Normalize dayOfWeek: both 0 and 7 mean Sunday; unify to 0
      if (field === "dayOfWeek" && value === 7) {
        valueSet.add(0);
      } else {
        valueSet.add(value);
      }
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must be a non-null string");
  }

  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

export type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  name: keyof ParsedCron;
  min: number;
  max: number;
};

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  }, // 7 = Sunday alias for 0
] as const;

function parseNonNegativeInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Invalid integer "${trimmed}" in ${context}`);
  }
  return parseInt(trimmed, 10);
}

function parseAtom(
  atom: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const trimmed = atom.trim();
  if (trimmed.length === 0) {
    throw new Error(`Empty atom in field "${fieldName}"`);
  }

  // Isolate optional step suffix (e.g. "*/15", "1-5/2", "3/10")
  let baseStr = trimmed;
  let step: number | undefined;
  const slashIdx = trimmed.indexOf("/");

  if (slashIdx !== -1) {
    baseStr = trimmed.slice(0, slashIdx);
    const stepStr = trimmed.slice(slashIdx + 1);
    if (stepStr.trim().length === 0) {
      throw new Error(`Missing step value after "/" in field "${fieldName}"`);
    }
    step = parseNonNegativeInteger(stepStr, `${fieldName} step`);
    if (step === 0) {
      throw new Error(`Step value cannot be zero in field "${fieldName}"`);
    }
  }

  let rangeMin: number;
  let rangeMax: number;

  if (baseStr === "*") {
    rangeMin = min;
    rangeMax = max;
  } else {
    const dashIdx = baseStr.indexOf("-");
    if (dashIdx === 0) {
      // Negative number masquerading as a range — reject it
      throw new Error(`Invalid atom "${trimmed}" in field "${fieldName}"`);
    }
    if (dashIdx !== -1) {
      const startStr = baseStr.slice(0, dashIdx);
      const endStr   = baseStr.slice(dashIdx + 1);
      if (endStr.trim().length === 0) {
        throw new Error(`Missing range end in "${trimmed}" in field "${fieldName}"`);
      }
      rangeMin = parseNonNegativeInteger(startStr, `${fieldName} range start`);
      rangeMax = parseNonNegativeInteger(endStr,   `${fieldName} range end`);
      if (rangeMin > rangeMax) {
        throw new Error(
          `Range start ${rangeMin} > end ${rangeMax} in field "${fieldName}"`
        );
      }
    } else {
      // Single numeric value; if a step is present treat it as value–max/step
      const val = parseNonNegativeInteger(baseStr, fieldName);
      rangeMin  = val;
      rangeMax  = step !== undefined ? max : val;
    }
  }

  if (rangeMin < min || rangeMax > max) {
    throw new Error(
      `Value(s) ${rangeMin}-${rangeMax} out of allowed range [${min}, ${max}] ` +
      `in field "${fieldName}"`
    );
  }

  const effectiveStep = step ?? 1;
  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += effectiveStep) {
    values.push(v);
  }
  return values;
}

function parseField(
  expr: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const parts = expr.split(",");
  if (parts.length === 0 || (parts.length === 1 && parts[0].trim() === "")) {
    throw new Error(`Empty field "${fieldName}"`);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (const v of parseAtom(part, min, max, fieldName)) {
      seen.add(v);
    }
  }

  // Return a sorted, deduplicated array
  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || expression.trim().length === 0) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, ` +
      `got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  const validate = (n: number): number => {
    if (n < min || n > max) {
      throw new RangeError(`Value ${n} out of range [${min}-${max}] for field "${field}"`);
    }
    return n;
  };

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}"`);
    }
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}"`);
    }
    const base = parseField(rangePart, field);
    const start = base[0];
    return base.filter((v) => (v - start) % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = validate(parseInt(startStr, 10));
    const end = validate(parseInt(endStr, 10));
    if (start > end) {
      throw new RangeError(`Invalid range ${start}-${end} for field "${field}"`);
    }
    return range(start, end);
  }

  const n = parseInt(expr, 10);
  if (isNaN(n)) {
    throw new SyntaxError(`Invalid value "${expr}" for field "${field}"`);
  }
  return [validate(n)];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);

      const rangeMin = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const rangeMax = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);

      validateRange(rangeMin, rangeMax, min, max);

      for (let i = rangeMin; i <= rangeMax; i += step) results.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const lo = parseInt(rangeMatch[1], 10);
      const hi = parseInt(rangeMatch[2], 10);
      validateRange(lo, hi, min, max);
      for (let i = lo; i <= hi; i++) results.add(i);
      continue;
    }

    if (/^\d+$/.test(trimmed)) {
      const val = parseInt(trimmed, 10);
      if (val < min || val > max) {
        throw new Error(`Value ${val} out of range [${min}, ${max}]`);
      }
      results.add(val);
      continue;
    }

    throw new Error(`Invalid cron field expression: "${trimmed}"`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateRange(lo: number, hi: number, min: number, max: number): void {
  if (lo > hi) throw new Error(`Invalid range: ${lo}-${hi} (start > end)`);
  if (lo < min || hi > max) {
    throw new Error(`Range ${lo}-${hi} out of bounds [${min}, ${max}]`);
  }
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max);
  }

  return result;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  // Range with optional step: n-m or n-m/s
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end = parseInt(rangeMatch[2], 10);
    const step = rangeMatch[3] ? parseInt(rangeMatch[3], 10) : 1;

    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);

    if (start > end) throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Step with base: n/s
  const stepBaseMatch = segment.match(/^(\d+)\/(\d+)$/);
  if (stepBaseMatch) {
    const start = parseInt(stepBaseMatch[1], 10);
    const step = parseInt(stepBaseMatch[2], 10);

    assertInRange(start, min, max, fieldName);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);

    const result: number[] = [];
    for (let i = start; i <= max; i += step) result.push(i);
    return result;
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    assertInRange(value, min, max, fieldName);
    return [value];
  }

  throw new SyntaxError(`Invalid segment "${segment}" in field "${fieldName}"`);
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  const segments = field.split(",");
  const values: number[] = [];

  for (const segment of segments) {
    values.push(...parseSegment(segment.trim(), min, max, fieldName));
  }

  return unique(values);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  const minute = parseField(minuteField, ...FIELD_RANGES.minute, "minute");
  const hour = parseField(hourField, ...FIELD_RANGES.hour, "hour");
  const dayOfMonth = parseField(domField, ...FIELD_RANGES.dayOfMonth, "dayOfMonth");
  const month = parseField(monthField, ...FIELD_RANGES.month, "month");

  // Parse dayOfWeek: normalize 7 -> 0 (both represent Sunday)
  let dayOfWeek = parseField(dowField, ...FIELD_RANGES.dayOfWeek, "dayOfWeek");
  dayOfWeek = unique(dayOfWeek.map((d) => (d === 7 ? 0 : d)));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function validateRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Invalid value ${value} in ${context}: must be an integer between ${min} and ${max}`
    );
  }
}

function parseSegment(segment: string, min: number, max: number, context: string): number[] {
  segment = segment.trim();

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step with wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) {
      throw new RangeError(`Invalid step value ${step} in ${context}: must be >= 1`);
    }
    const values: number[] = [];
    for (let v = min; v <= max; v += step) {
      values.push(v);
    }
    return values;
  }

  // Step with range: n-m/s
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const start = parseInt(stepRangeMatch[1], 10);
    const end = parseInt(stepRangeMatch[2], 10);
    const step = parseInt(stepRangeMatch[3], 10);
    validateRange(start, min, max, context);
    validateRange(end, min, max, context);
    if (start > end) {
      throw new RangeError(`Invalid range ${start}-${end} in ${context}: start must be <= end`);
    }
    if (step < 1) {
      throw new RangeError(`Invalid step value ${step} in ${context}: must be >= 1`);
    }
    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Plain range: n-m
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end = parseInt(rangeMatch[2], 10);
    validateRange(start, min, max, context);
    validateRange(end, min, max, context);
    if (start > end) {
      throw new RangeError(`Invalid range ${start}-${end} in ${context}: start must be <= end`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    validateRange(value, min, max, context);
    return [value];
  }

  throw new SyntaxError(`Unrecognized cron segment "${segment}" in ${context}`);
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — each part may itself be a range, step, wildcard, or number
  const parts = expression.split(",");
  if (parts.length > 1) {
    // Wildcards inside a list are semantically odd but we'll reject them explicitly
    if (parts.some((p) => p.trim() === "*" || p.trim().startsWith("*/"))) {
      throw new SyntaxError(
        `Wildcard cannot appear inside a comma-separated list in field "${field}"`
      );
    }
    const seen = new Set<number>();
    for (const part of parts) {
      for (const v of parseSegment(part, min, max, field)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(expression.trim(), min, max, field);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected exactly 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  },
] as const satisfies FieldConfig[];

function assertInteger(raw: string, fieldName: string): number {
  if (raw === "" || !/^\d+$/.test(raw)) {
    throw new RangeError(
      `Invalid value "${raw}" in field "${fieldName}": expected a non-negative integer`
    );
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, min: number, max: number, fieldName: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function buildRange(
  start: number,
  end: number,
  step: number,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer in field "${fieldName}", got ${step}`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${fieldName}"`
    );
  }
  assertInRange(start, min, max, fieldName);
  assertInRange(end,   min, max, fieldName);

  const result: number[] = [];
  for (let v = start; v <= end; v += step) {
    result.push(v);
  }
  return result;
}

function parseToken(token: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  // Step: */n  |  a-b/n  |  a/n  (start from a to max)
  const slashPos = token.indexOf("/");
  if (slashPos !== -1) {
    const baseRaw = token.slice(0, slashPos);
    const stepRaw = token.slice(slashPos + 1);

    if (stepRaw === "" || stepRaw.includes("/")) {
      throw new SyntaxError(`Malformed step expression "${token}" in field "${name}"`);
    }

    const step = assertInteger(stepRaw, name);

    if (baseRaw === "*") {
      return buildRange(min, max, step, min, max, name);
    }

    const dashPos = baseRaw.indexOf("-");
    if (dashPos !== -1) {
      const start = assertInteger(baseRaw.slice(0, dashPos), name);
      const end   = assertInteger(baseRaw.slice(dashPos + 1), name);
      return buildRange(start, end, step, min, max, name);
    }

    // n/step — treat n as start, max as end
    const start = assertInteger(baseRaw, name);
    assertInRange(start, min, max, name);
    return buildRange(start, max, step, min, max, name);
  }

  // Wildcard
  if (token === "*") {
    return buildRange(min, max, 1, min, max, name);
  }

  // Range: a-b
  const dashPos = token.indexOf("-");
  if (dashPos !== -1) {
    // Protect against a leading "-" being misread as a range separator
    if (dashPos === 0) {
      throw new SyntaxError(`Negative numbers are not permitted in field "${name}": "${token}"`);
    }
    const start = assertInteger(token.slice(0, dashPos), name);
    const end   = assertInteger(token.slice(dashPos + 1), name);
    return buildRange(start, end, 1, min, max, name);
  }

  // Single value
  const value = assertInteger(token, name);
  assertInRange(value, min, max, name);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (!raw || raw.trim() === "") {
    throw new SyntaxError(`Field "${config.name}" is empty`);
  }

  const tokens = raw.split(",");
  const seen = new Set<number>();

  for (const tok of tokens) {
    const trimmed = tok.trim();
    if (trimmed === "") {
      throw new SyntaxError(
        `Empty token in comma-separated list for field "${config.name}"`
      );
    }
    for (const v of parseToken(trimmed, config)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(`Field "${config.name}" resolved to no valid values`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must contain exactly 5 fields (got ${parts.length}): "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = parts;

  return {
    minute:     parseField(minuteRaw,     FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,       FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,      FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dayOfWeekRaw,  FIELD_CONFIGS[4]),
  };
}

type NestedObject = { [key: string]: unknown };
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at path: "${prefix || "<root>"}"`
    );
  }

  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const childKeys = Object.keys(value);
      if (childKeys.length === 0) {
        // Empty plain object — preserve as a leaf so the key is not silently dropped
        result[fullKey] = value;
      } else {
        flattenInto(value, fullKey, result, ancestors);
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove after processing so sibling branches can reference the same object
  // without triggering a false-positive circular-reference error
  ancestors.delete(obj);
}

export default function flattenObject(obj: NestedObject): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, got: ${obj === null ? "null" : typeof obj}`
    );
  }

  const result: FlatObject = {};
  flattenInto(obj, "", result, new WeakSet());
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix: string = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) {
    return result;
  }

  if (typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix !== "") {
      result[prefix] = obj as Primitive;
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0 && prefix !== "") {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<keyof CronResult, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

const FIELD_ORDER: ReadonlyArray<keyof CronResult> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function parseIntStrict(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Non-numeric value "${raw}" in "${context}"`);
  }
  return parseInt(raw, 10);
}

function assertInBounds(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} out of range [${config.min}, ${config.max}] in "${context}"`
    );
  }
}

function expandValues(
  start: number,
  end: number,
  step: number,
  config: FieldConfig,
  context: string
): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step} in "${context}"`);
  }
  if (start > end) {
    throw new Error(
      `Range start ${start} exceeds end ${end} in "${context}"`
    );
  }
  assertInBounds(start, config, context);
  assertInBounds(end, config, context);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  // Step expression: "*/n", "a-b/n", or "a/n"
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Malformed step expression: "${segment}"`);
    }
    const [rangePart, stepStr] = slashParts;
    const step = parseIntStrict(stepStr, segment);

    if (rangePart === "*") {
      return expandValues(config.min, config.max, step, config, segment);
    }

    if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Malformed range in step expression: "${segment}"`);
      }
      const start = parseIntStrict(dashParts[0], segment);
      const end   = parseIntStrict(dashParts[1], segment);
      return expandValues(start, end, step, config, segment);
    }

    // "a/n" — start at a, step to max
    const start = parseIntStrict(rangePart, segment);
    return expandValues(start, config.max, step, config, segment);
  }

  // Plain range: "a-b"
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Malformed range expression: "${segment}"`);
    }
    const start = parseIntStrict(dashParts[0], segment);
    const end   = parseIntStrict(dashParts[1], segment);
    return expandValues(start, end, 1, config, segment);
  }

  // Wildcard
  if (segment === "*") {
    return expandValues(config.min, config.max, 1, config, segment);
  }

  // Single numeric value
  const value = parseIntStrict(segment, segment);
  assertInBounds(value, config, segment);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (field === "" || field.trim() === "") {
    throw new Error("Empty cron field encountered");
  }

  const parts = field.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in comma list: "${field}"`);
    }
    for (const v of parseSegment(trimmed, config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    try {
      result[name] = parseField(fields[i], FIELD_CONFIGS[name]);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid ${name} field ("${fields[i]}"): ${message}`);
    }
  }

  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS = [
  { min: 0,  max: 59, name: "minute"     },
  { min: 0,  max: 23, name: "hour"       },
  { min: 1,  max: 31, name: "dayOfMonth" },
  { min: 1,  max: 12, name: "month"      },
  { min: 0,  max: 7,  name: "dayOfWeek"  },
] as const satisfies readonly FieldConfig[];

function parseInteger(raw: string, context: string): number {
  const n = parseInt(raw, 10);
  if (isNaN(n) || String(n) !== raw.trim()) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range for ${config.name} (${config.min}-${config.max})`
    );
  }
}

function expandStep(rangeStr: string, stepStr: string, config: FieldConfig): number[] {
  const step = parseInteger(stepStr, `${config.name} step`);
  if (step <= 0) {
    throw new RangeError(`Step must be positive in ${config.name}, got ${step}`);
  }

  let rangeMin = config.min;
  let rangeMax = config.max;

  if (rangeStr !== "*") {
    if (rangeStr.includes("-")) {
      [rangeMin, rangeMax] = expandRange(rangeStr, config, true);
    } else {
      rangeMin = parseInteger(rangeStr, config.name);
      assertInRange(rangeMin, config);
    }
  }

  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    values.push(i);
  }
  return values;
}

function expandRange(expr: string, config: FieldConfig, returnBounds: true): [number, number];
function expandRange(expr: string, config: FieldConfig, returnBounds?: false): number[];
function expandRange(
  expr: string,
  config: FieldConfig,
  returnBounds = false
): number[] | [number, number] {
  const parts = expr.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range "${expr}" in ${config.name}`);
  }

  const start = parseInteger(parts[0], `${config.name} range start`);
  const end   = parseInteger(parts[1], `${config.name} range end`);

  assertInRange(start, config);
  assertInRange(end, config);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in ${config.name}`
    );
  }

  if (returnBounds) return [start, end];

  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(expr: string, config: FieldConfig): number[] {
  if (expr === "*") {
    return Array.from({ length: config.max - config.min + 1 }, (_, i) => config.min + i);
  }

  if (expr.includes("/")) {
    const slashIdx = expr.indexOf("/");
    const rangeStr = expr.slice(0, slashIdx);
    const stepStr  = expr.slice(slashIdx + 1);
    if (!rangeStr || !stepStr) {
      throw new Error(`Malformed step expression "${expr}" in ${config.name}`);
    }
    return expandStep(rangeStr, stepStr, config);
  }

  if (expr.includes("-")) {
    return expandRange(expr, config);
  }

  const value = parseInteger(expr, config.name);
  assertInRange(value, config);
  return [value];
}

function parseField(expr: string, config: FieldConfig): number[] {
  if (!expr || expr.trim() === "") {
    throw new Error(`Empty expression for field ${config.name}`);
  }

  const segments = expr.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new Error(`Trailing or consecutive commas in ${config.name} field`);
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), config)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute:     parseField(minuteExpr,     FIELD_CONFIGS[0]),
    hour:       parseField(hourExpr,       FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthExpr, FIELD_CONFIGS[2]),
    month:      parseField(monthExpr,      FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dayOfWeekExpr,  FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

type Scalar = string | number | boolean | null | undefined | bigint | symbol;

function isTraversable(value: unknown): value is Record<string | number, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof WeakMap) return false;
  if (value instanceof WeakSet) return false;
  if (ArrayBuffer.isView(value)) return false;
  return true;
}

function flatten(
  input: Record<string | number, unknown>,
  prefix: string,
  ancestors: WeakSet<object>,
  result: Record<string, Scalar | Date | RegExp | Map<unknown, unknown> | Set<unknown>>
): void {
  const keys = Array.isArray(input) ? [...input.keys()] : Object.keys(input);

  for (const key of keys) {
    const value = input[key as keyof typeof input];
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : String(key);

    if (isTraversable(value)) {
      const ownKeys = Array.isArray(value) ? value.length : Object.keys(value).length;

      if (ownKeys === 0) {
        // Preserve empty objects/arrays as leaf values — losing them silently would be wrong
        result[fullKey] = value as never;
        continue;
      }

      if (ancestors.has(value)) {
        // Circular reference: surface as a sentinel rather than silently dropping or looping forever
        result[fullKey] = "[Circular]";
        continue;
      }

      ancestors.add(value);
      flatten(value, fullKey, ancestors, result);
      ancestors.delete(value); // remove after descent so sibling paths with same ref are handled correctly
    } else {
      result[fullKey] = value as Scalar;
    }
  }
}

export default function flattenObject(
  input: Record<string, unknown>
): Record<string, unknown> {
  if (input === null || typeof input !== "object") {
    throw new TypeError(
      `flattenObject expects a plain object, received ${input === null ? "null" : typeof input}`
    );
  }

  if (!isTraversable(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received a special object type (Date, Map, RegExp, etc.)`
    );
  }

  const result: Record<string, unknown> = {};
  flatten(input as Record<string | number, unknown>, "", new WeakSet(), result as never);
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: CronField;
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
];

function rangeArray(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`${context}: value ${value} is outside the valid range [${min}, ${max}]`);
  }
}

function parseToken(token: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  if (!token || token.trim() === "") {
    throw new SyntaxError(`Field "${name}": empty token`);
  }

  // Step notation: e.g. "*/15" or "1-10/2"
  const stepSlash = token.indexOf("/");
  if (stepSlash !== -1) {
    const baseRaw = token.slice(0, stepSlash);
    const stepRaw = token.slice(stepSlash + 1);

    if (!stepRaw || !/^\d+$/.test(stepRaw)) {
      throw new SyntaxError(`Field "${name}": invalid step value in "${token}"`);
    }
    const step = parseInt(stepRaw, 10);
    if (step <= 0) {
      throw new RangeError(`Field "${name}": step must be ≥ 1, got ${step}`);
    }

    let start: number;
    let end: number;

    if (baseRaw === "*") {
      start = min;
      end = max;
    } else {
      const rangeDash = baseRaw.indexOf("-");
      if (rangeDash === -1) {
        if (!/^\d+$/.test(baseRaw)) {
          throw new SyntaxError(`Field "${name}": invalid base in step expression "${token}"`);
        }
        start = parseInt(baseRaw, 10);
        end = max;
      } else {
        const startRaw = baseRaw.slice(0, rangeDash);
        const endRaw = baseRaw.slice(rangeDash + 1);
        if (!/^\d+$/.test(startRaw) || !/^\d+$/.test(endRaw)) {
          throw new SyntaxError(`Field "${name}": invalid range in step expression "${token}"`);
        }
        start = parseInt(startRaw, 10);
        end = parseInt(endRaw, 10);
      }
    }

    assertInRange(start, min, max, `Field "${name}" range start`);
    assertInRange(end, min, max, `Field "${name}" range end`);
    if (start > end) {
      throw new RangeError(`Field "${name}": range start ${start} is greater than end ${end}`);
    }

    return rangeArray(start, end, step);
  }

  // Wildcard
  if (token === "*") {
    return rangeArray(min, max, 1);
  }

  // Range: e.g. "1-5"
  const dashIndex = token.indexOf("-");
  if (dashIndex !== -1) {
    const startRaw = token.slice(0, dashIndex);
    const endRaw = token.slice(dashIndex + 1);

    if (!/^\d+$/.test(startRaw) || !/^\d+$/.test(endRaw)) {
      throw new SyntaxError(`Field "${name}": invalid range expression "${token}"`);
    }

    const start = parseInt(startRaw, 10);
    const end = parseInt(endRaw, 10);

    assertInRange(start, min, max, `Field "${name}" range start`);
    assertInRange(end, min, max, `Field "${name}" range end`);

    if (start > end) {
      throw new RangeError(`Field "${name}": range start ${start} is greater than end ${end} in "${token}"`);
    }

    return rangeArray(start, end, 1);
  }

  // Literal number
  if (/^\d+$/.test(token)) {
    const value = parseInt(token, 10);
    assertInRange(value, min, max, `Field "${name}"`);
    return [value];
  }

  throw new SyntaxError(`Field "${name}": unrecognised token "${token}"`);
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw == null || raw.trim() === "") {
    throw new SyntaxError(`Field "${config.name}" is missing or empty`);
  }

  const parts = raw.split(",");
  if (parts.length === 0) {
    throw new SyntaxError(`Field "${config.name}" produced no parts after split`);
  }

  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) {
      throw new SyntaxError(`Field "${config.name}": empty element in comma-separated list "${raw}"`);
    }
    for (const v of parseToken(trimmed, config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (expression == null) {
    throw new TypeError("parseCron: expression must not be null or undefined");
  }
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError("parseCron: expression must not be empty");
  }

  // Split on any run of whitespace, guarding against leading/trailing whitespace artifacts
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `parseCron: expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length} in "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    // Guard: this should never be undefined given the length check above, but be explicit
    const raw = fields[i];
    if (raw === undefined) {
      throw new RangeError(`parseCron: missing field at index ${i} ("${config.name}")`);
    }
    result[config.name] = parseField(raw, config);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
      return result;
    }
    for (let i = 0; i < obj.length; i++) {
      const key = prefix ? `${prefix}.${i}` : String(i);
      flattenObject(obj[i] as NestedObject, key, result);
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const k of keys) {
    const key = prefix ? `${prefix}.${k}` : k;
    const value = obj[k];
    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, key, result);
    } else {
      result[key] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlattenedObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  for (const [key, value] of Object.entries(obj)) {
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, flatKey, result);
    } else {
      result[flatKey] = Array.isArray(value) ? JSON.stringify(value) : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function assertInRange(
  value: number,
  field: CronField,
  context: string
): void {
  const { min, max } = FIELD_RANGES[field];
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new CronParseError(
      `Value ${value} out of range [${min}-${max}] for field "${field}" in "${context}"`
    );
  }
}

function deduplicateAndSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseNumber(token: string, field: CronField): number {
  const n = Number(token);
  if (!Number.isFinite(n) || token.trim() === "") {
    throw new CronParseError(
      `Invalid numeric value "${token}" for field "${field}"`
    );
  }
  const integer = Math.trunc(n);
  assertInRange(integer, field, token);
  return integer;
}

function expandRange(
  rawRange: string,
  field: CronField,
  step: number
): number[] {
  const rangeParts = rawRange.split("-");

  if (rangeParts.length !== 2) {
    throw new CronParseError(
      `Invalid range expression "${rawRange}" for field "${field}"`
    );
  }

  const [startRaw, endRaw] = rangeParts;
  const start = parseNumber(startRaw, field);
  const end = parseNumber(endRaw, field);

  if (start > end) {
    throw new CronParseError(
      `Range start ${start} exceeds end ${end} for field "${field}"`
    );
  }

  if (step < 1) {
    throw new CronParseError(
      `Step value ${step} must be >= 1 for field "${field}"`
    );
  }

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function expandWildcard(field: CronField, step: number): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (step < 1) {
    throw new CronParseError(
      `Step value ${step} must be >= 1 for field "${field}"`
    );
  }

  const values: number[] = [];
  for (let v = min; v <= max; v += step) {
    values.push(v);
  }
  return values;
}

function normalizeDay(values: number[]): number[] {
  // dayOfWeek: treat 7 as an alias for 0 (Sunday)
  return deduplicateAndSort(
    values.map((v) => (v === 7 ? 0 : v))
  );
}

function parseSegment(token: string, field: CronField): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty segment encountered for field "${field}"`);
  }

  // Step expression: base/step
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new CronParseError(
        `Invalid step expression "${trimmed}" for field "${field}"`
      );
    }

    const [base, stepRaw] = slashParts;
    const step = Number(stepRaw);

    if (!Number.isInteger(step) || step < 1) {
      throw new CronParseError(
        `Invalid step "${stepRaw}" in expression "${trimmed}" for field "${field}"`
      );
    }

    if (base === "*") {
      return expandWildcard(field, step);
    }

    if (base.includes("-")) {
      return expandRange(base, field, step);
    }

    // single-number base with step: treat as range from base to max
    const start = parseNumber(base, field);
    const { max } = FIELD_RANGES[field];
    const values: number[] = [];
    for (let v = start; v <= max; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (trimmed === "*") {
    return expandWildcard(field, 1);
  }

  // Range: start-end
  if (trimmed.includes("-")) {
    return expandRange(trimmed, field, 1);
  }

  // Single numeric value
  return [parseNumber(trimmed, field)];
}

function parseField(raw: string, field: CronField): number[] {
  if (raw == null || raw.trim() === "") {
    throw new CronParseError(`Missing or empty value for field "${field}"`);
  }

  const segments = raw.split(",");

  if (segments.length === 0) {
    throw new CronParseError(`No segments found in field "${field}"`);
  }

  const values = segments.flatMap((segment) => parseSegment(segment, field));

  // Validate all collected values fall within range before returning
  const { min, max } = FIELD_RANGES[field];
  for (const v of values) {
    if (v < min || v > max) {
      throw new CronParseError(
        `Resolved value ${v} is out of range [${min}-${max}] for field "${field}"`
      );
    }
  }

  const sorted = deduplicateAndSort(values);

  // Normalize Sunday alias for dayOfWeek
  return field === "dayOfWeek" ? normalizeDay(sorted) : sorted;
}

export default function parseCron(expression: string): CronExpression {
  if (expression == null) {
    throw new CronParseError("Cron expression must not be null or undefined");
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  // Collapse multiple whitespace characters between fields
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(
      `Expected exactly 5 fields, got ${fields.length} in expression "${trimmed}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function validateRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${field}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        if (isNaN(lo) || isNaN(hi)) {
          throw new SyntaxError(`Invalid range "${rangePart}" in field "${field}"`);
        }
        validateRange(lo, min, max, field);
        validateRange(hi, min, max, field);
        if (lo > hi) {
          throw new RangeError(`Range start ${lo} > end ${hi} in field "${field}"`);
        }
        rangeMin = lo;
        rangeMax = hi;
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new SyntaxError(`Invalid step expression "${segment}" in field "${field}"`);
        }
        validateRange(start, min, max, field);
        rangeMin = start;
      }
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const lo = parseInt(parts[0], 10);
    const hi = parseInt(parts[1], 10);
    if (isNaN(lo) || isNaN(hi)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    validateRange(lo, min, max, field);
    validateRange(hi, min, max, field);
    if (lo > hi) {
      throw new RangeError(`Range start ${lo} > end ${hi} in field "${field}"`);
    }
    const values: number[] = [];
    for (let i = lo; i <= hi; i++) {
      values.push(i);
    }
    return values;
  }

  // Wildcard: *
  if (segment === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Literal number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  validateRange(num, min, max, field);
  return [num];
}

function parseField(expression: string, min: number, max: number, field: string): number[] {
  const segments = expression.split(",");
  const values: number[] = [];

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    values.push(...parseSegment(trimmed, min, max, field));
  }

  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  if (field === "dayOfWeek") {
    return unique(values.map(v => v === 7 ? 0 : v));
  }

  return unique(values);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteExpr,
    hourExpr,
    dayOfMonthExpr,
    monthExpr,
    dayOfWeekExpr,
  ].map((expr, i) => {
    const name = fieldNames[i];
    const { min, max } = FIELD_RANGES[name];
    return parseField(expr, min, max, name);
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}
